#### 5.2 Pinia Stores 测试

```typescript
// tests/dashboard/frontend/stores/iteration.test.ts

import { setActivePinia, createPinia } from 'pinia';
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { useIterationStore } from '@/stores/iteration';

describe('Iteration Store', () => {
  beforeEach(() => {
    setActivePinia(createPinia());
  });

  it('初始状态应该正确', () => {
    const store = useIterationStore();
    expect(store.iterations).toEqual([]);
    expect(store.currentIteration).toBeNull();
    expect(store.loading).toBe(false);
  });

  it('应该正确设置当前迭代', () => {
    const store = useIterationStore();
    const mockIteration = { id: 1, status: 'running' };
    store.setCurrentIteration(mockIteration);
    expect(store.currentIteration).toEqual(mockIteration);
  });

  it('loadIterations 应该加载数据', async () => {
    const store = useIterationStore();
    // Mock API call
    await store.loadIterations();
    expect(store.iterations.length).toBeGreaterThan(0);
  });
});
```

#### 5.3 Vue 组件测试

```typescript
// tests/dashboard/frontend/components/Dashboard.test.ts

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { mount } from '@vue/test-utils';
import { createPinia } from 'pinia';
import Dashboard from '@/components/Dashboard.vue';

describe('Dashboard Component', () => {
  let wrapper: any;

  beforeEach(() => {
    const pinia = createPinia();
    wrapper = mount(Dashboard, {
      global: { plugins: [pinia] }
    });
  });

  it('应该正确渲染', () => {
    expect(wrapper.exists()).toBe(true);
    expect(wrapper.find('.dashboard').exists()).toBe(true);
  });

  it('应该显示系统概览卡片', () => {
    expect(wrapper.find('.system-overview').exists()).toBe(true);
  });

  it('点击开始按钮应该触发 startIteration', async () => {
    const startSpy = vi.spyOn(wrapper.vm, 'startIteration');
    await wrapper.find('.start-button').trigger('click');
    expect(startSpy).toHaveBeenCalled();
  });
});
```

